module.exports = function(RED) {
    "use strict";

    function NeuralSigmoidNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;

        node.on("input", function(msg, send, done) {
            var input = msg.payload;
            if (!Array.isArray(input)) {
                input = [input];
            }

            var output = input.map(function(v) { return 1 / (1 + Math.exp(-v)); });

            msg.payload = output;
            msg.neural = msg.neural || {};
            msg.neural.type = "sigmoid";
            msg.neural.shape = [output.length];

            node.status({ fill: "green", shape: "dot", text: output.map(function(v) { return v.toFixed(2); }).join(", ") });

            send(msg);
            done();
        });
    }

    RED.nodes.registerType("neural-sigmoid", NeuralSigmoidNode);
};
